using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Configure options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented    = true
};

// ── 1. Strongly-typed metadata retrieval ──────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly – no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type:       {personInfo.Type.Name}");
Console.WriteLine($"Kind:       {personInfo.Kind}");
Console.WriteLine($"Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");
Console.WriteLine();

// Round-trip using the typed metadata
var alice = new Person("Alice", 30);
string json = JsonSerializer.Serialize(alice, personInfo);
Console.WriteLine($"Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {deserialized}");
Console.WriteLine();

// ── 2. Probe without throwing ─────────────────────────────────────
// TryGetTypeInfo<T>() returns false instead of throwing when metadata
// for T is unavailable.

// 2a. A type the resolver knows about:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"Person metadata available  – Kind: {found.Kind}");
else
    Console.WriteLine("Person metadata NOT available");

// 2b. A type the resolver will NOT resolve (custom resolver that
//     only handles Person):
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (limited.TryGetTypeInfo<int[]>(out _))
    Console.WriteLine("int[] metadata available");
else
    Console.WriteLine("int[] metadata NOT available  – no exception thrown");

// ───────────────────────────────────────────────────────────────────
public record Person(string Name, int Age);

/// <summary>A resolver that only provides metadata for <see cref="Person"/>.</summary>
file sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}
